class Solution:
    def magicalString(self, n: int) -> int:
        if n == 0:
            return 0
        if n <= 3:
            return 1
        s = [1, 2, 2]
        idx = 2
        count = 1
        next_val = 1
        while len(s) < n:
            repeat = s[idx]
            for _ in range(repeat):
                s.append(next_val)
                if next_val == 1 and len(s) <= n:
                    count += 1
            next_val = 3 - next_val
            idx += 1
        return count

